#include <cstdio>
#include <cstdlib>
#include <iostream>
#include <iomanip>
#include <cmath>
#include <limits>
#include <ctime>
#include <chrono>
#include <vector>
#include <cuda_runtime.h>

#define N 2048
#define IDX(i, j) ((i) + (j) * N)

static constexpr float PI_F = 3.14159265358979323846f;

void initialize_data(float* f) {
  for (int j = 0; j < N; ++j) {
    for (int i = 0; i < N; ++i) {
      if (i == 0 || i == N - 1) {
        f[IDX(i, j)] = sinf(j * 2.0f * PI_F / (N - 1));
      } else if (j == 0 || j == N - 1) {
        f[IDX(i, j)] = sinf(i * 2.0f * PI_F / (N - 1));
      } else {
        f[IDX(i, j)] = 0.0f;
      }
    }
  }
}

__global__ void jacobi_kernel(const float* f_old, float* f, float* partials) {
  __shared__ float sdata[256];

  const unsigned int tid = threadIdx.x;
  const unsigned int gid = blockIdx.x * blockDim.x + threadIdx.x;
  const unsigned int interior = (N - 2) * (N - 2);

  float local = 0.0f;

  if (gid < interior) {
    const int i = 1 + (gid % (N - 2));
    const int j = 1 + (gid / (N - 2));

    float t = 0.25f * (f_old[IDX(i - 1, j)] +
                       f_old[IDX(i + 1, j)] +
                       f_old[IDX(i, j - 1)] +
                       f_old[IDX(i, j + 1)]);
    float df = t - f_old[IDX(i, j)];
    f[IDX(i, j)] = t;
    local = df * df;
  }

  sdata[tid] = local;
  __syncthreads();

  for (unsigned int s = blockDim.x / 2; s > 0; s >>= 1) {
    if (tid < s) {
      sdata[tid] += sdata[tid + s];
    }
    __syncthreads();
  }

  if (tid == 0) {
    partials[blockIdx.x] = sdata[0];
  }
}

__global__ void copy_kernel(const float* f, float* f_old) {
  const unsigned int gid = blockIdx.x * blockDim.x + threadIdx.x;
  const unsigned int interior = (N - 2) * (N - 2);

  if (gid < interior) {
    const int i = 1 + (gid % (N - 2));
    const int j = 1 + (gid / (N - 2));
    f_old[IDX(i, j)] = f[IDX(i, j)];
  }
}

int main() {
  auto start_time = std::chrono::steady_clock::now();

  float* f = nullptr;
  float* f_old = nullptr;
  posix_memalign(reinterpret_cast<void**>(&f), 64, N * N * sizeof(float));
  posix_memalign(reinterpret_cast<void**>(&f_old), 64, N * N * sizeof(float));

  float error = std::numeric_limits<float>::max();
  const float tolerance = 1.e-5f;

  initialize_data(f);
  initialize_data(f_old);

  const int max_iters = 10000;
  int num_iters = 0;

  float* d_f = nullptr;
  float* d_f_old = nullptr;
  float* d_partials = nullptr;

  const size_t bytes = static_cast<size_t>(N) * static_cast<size_t>(N) * sizeof(float);
  const int interior = (N - 2) * (N - 2);
  const int block_size = 256;
  const int num_blocks = (interior + block_size - 1) / block_size;

  cudaMalloc(&d_f, bytes);
  cudaMalloc(&d_f_old, bytes);
  cudaMalloc(&d_partials, static_cast<size_t>(num_blocks) * sizeof(float));

  cudaMemcpy(d_f, f, bytes, cudaMemcpyHostToDevice);
  cudaMemcpy(d_f_old, f_old, bytes, cudaMemcpyHostToDevice);

  std::vector<float> h_partials(num_blocks);

  {
    auto start = std::chrono::steady_clock::now();

    while (error > tolerance && num_iters < max_iters) {
      error = 0.0f;

      jacobi_kernel<<<num_blocks, block_size>>>(d_f_old, d_f, d_partials);
      cudaMemcpy(h_partials.data(), d_partials, static_cast<size_t>(num_blocks) * sizeof(float), cudaMemcpyDeviceToHost);

      copy_kernel<<<num_blocks, block_size>>>(d_f, d_f_old);
      cudaDeviceSynchronize();

      for (int i = 0; i < num_blocks; ++i) {
        error += h_partials[i];
      }

      error = sqrtf(error / (N * N));

      if (num_iters % 1000 == 0) {
        std::cout << "Error after iteration " << num_iters << " = " << error << std::endl;
      }

      ++num_iters;
    }

    auto end = std::chrono::steady_clock::now();
    auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
    std::cout << "Average execution time per iteration: " << (time * 1e-9f) / num_iters << " (s)\n";
  }

  if (error <= tolerance && num_iters < max_iters) {
    std::cout << "PASS" << std::endl;
  } else {
    std::cout << "FAIL" << std::endl;
    return -1;
  }

  cudaFree(d_f);
  cudaFree(d_f_old);
  cudaFree(d_partials);

  free(f);
  free(f_old);

  auto end_time = std::chrono::steady_clock::now();
  auto total_time = std::chrono::duration_cast<std::chrono::nanoseconds>(end_time - start_time).count();
  double duration = total_time * 1e-9;
  std::cout << "Total elapsed time: " << std::setprecision(4) << duration << " seconds" << std::endl;

  return 0;
}
